@page "/account/login"
@using Microsoft.AspNetCore.Identity
@using System.ComponentModel.DataAnnotations
@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Login</PageTitle>

<h1>Login</h1>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row">
    <div class="col-md-4">
        <form method="post" @formname="login" @onsubmit="LoginUser">
            <AntiforgeryToken />
            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="Input.Email" class="form-control" autocomplete="username" />
            </div>
            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="Input.Password" type="password" class="form-control" autocomplete="current-password" />
            </div>
            <div class="mb-3 form-check">
                <InputCheckbox id="rememberMe" @bind-Value="Input.RememberMe" class="form-check-input" />
                <label for="rememberMe" class="form-check-label">Remember me</label>
            </div>
            <button type="submit" class="btn btn-primary">Log in</button>
        </form>
        <div class="mt-3">
            <p><a href="/account/register">Register as a new user</a></p>
        </div>
    </div>
</div>

@code {
    [Inject] private SignInManager<IdentityUser> SignInManager { get; set; } = default!;
    [Inject] private NavigationManager NavigationManager { get; set; } = default!;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    private string? errorMessage;

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(
            Input.Email, Input.Password, Input.RememberMe, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            NavigationManager.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid login attempt.";
        }
    }

    private sealed class LoginInput
    {
        [Required]
        [EmailAddress]
        public string Email { get; set; } = "";

        [Required]
        [DataType(DataType.Password)]
        public string Password { get; set; } = "";

        public bool RememberMe { get; set; }
    }
}

@page "/account/register"
@using Microsoft.AspNetCore.Identity
@using System.ComponentModel.DataAnnotations
@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Register</PageTitle>

<h1>Register</h1>

@if (errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

<div class="row">
    <div class="col-md-4">
        <form method="post" @formname="register" @onsubmit="RegisterUser">
            <AntiforgeryToken />
            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="Input.Email" class="form-control" autocomplete="username" />
            </div>
            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="Input.Password" type="password" class="form-control" autocomplete="new-password" />
            </div>
            <div class="mb-3">
                <label for="confirmPassword" class="form-label">Confirm Password</label>
                <InputText id="confirmPassword" @bind-Value="Input.ConfirmPassword" type="password" class="form-control" autocomplete="new-password" />
            </div>
            <button type="submit" class="btn btn-primary">Register</button>
        </form>
        <div class="mt-3">
            <p><a href="/account/login">Already have an account? Log in</a></p>
        </div>
    </div>
</div>

@code {
    [Inject] private UserManager<IdentityUser> UserManager { get; set; } = default!;
    [Inject] private SignInManager<IdentityUser> SignInManager { get; set; } = default!;
    [Inject] private NavigationManager NavigationManager { get; set; } = default!;

    [SupplyParameterFromForm]
    private RegisterInput Input { get; set; } = new();

    private List<string> errors = new();

    private async Task RegisterUser()
    {
        errors.Clear();

        if (Input.Password != Input.ConfirmPassword)
        {
            errors.Add("Passwords do not match.");
            return;
        }

        var user = new IdentityUser { UserName = Input.Email, Email = Input.Email };
        var result = await UserManager.CreateAsync(user, Input.Password);

        if (result.Succeeded)
        {
            await SignInManager.SignInAsync(user, isPersistent: false);
            NavigationManager.NavigateTo("/", forceLoad: true);
        }
        else
        {
            foreach (var error in result.Errors)
            {
                errors.Add(error.Description);
            }
        }
    }

    private sealed class RegisterInput
    {
        [Required]
        [EmailAddress]
        public string Email { get; set; } = "";

        [Required]
        [DataType(DataType.Password)]
        [StringLength(100, MinimumLength = 6)]
        public string Password { get; set; } = "";

        [Required]
        [DataType(DataType.Password)]
        [Compare(nameof(Password))]
        public string ConfirmPassword { get; set; } = "";
    }
}

